  1→import './editor.css';
  2→import { motion } from "framer-motion";
  3→import React, { useCallback, useEffect, useState } from 'react';
  4→import { useLexicalComposerContext } from "@lexical/react/LexicalComposerContext";
  5→import EditorInner from './RichTextEditor.jsx';
  6→import CanvasEditor from '../Canvas/CanvasEditor.jsx';
  7→import { $getRoot } from 'lexical';
  8→import { deleteJournalImage } from '../../../../API/Api.js';
  9→import { useAuth } from '../../../Context/useAuth.js';
 10→
 11→class ErrorBoundary extends React.Component {
 12→  state = { error: null };
 13→  static getDerivedStateFromError(error) {
 14→    return { error };
 15→  }
 16→  render() {
 17→    if (this.state.error) {
 18→      return <div>Error: {this.state.error.message}</div>;
 19→    }
 20→    return this.props.children;
 21→  }
 22→}
 23→
 24→const Editor=({onClose, initialMode = 'text', initialTitle = '', initialCanvasDoc = null, remixSource = null}) =>{
 25→    const {session} = useAuth();
 26→
 27→    const [editorMode, setEditorMode] = useState(initialMode === 'canvas' ? 'canvas' : 'text');
 28→    const [title, setTitle] = useState(initialTitle || '')
 29→    const [wordCount, setWordCount] = useState(0);
 30→    const [editor] = useLexicalComposerContext();
 31→
 32→
 33→    const [uploadedImagePaths, setUploadedImagePaths] = useState([]);
 34→
 35→    const addUploadedImagePath = useCallback((imagePath) =>{
 36→      setUploadedImagePaths((prev) => [...prev, imagePath]);
 37→    }, [])
 38→
 39→    useEffect(() => {
 40→        setEditorMode(initialMode === 'canvas' ? 'canvas' : 'text');
 41→        setTitle(initialTitle || '');
 42→    }, [initialMode, initialTitle]);
 43→
 44→    const handleCloseEditor = useCallback(async() => {
 45→      if(uploadedImagePaths.length > 0){
 46→        const message = await deleteJournalImage(session?.access_token, uploadedImagePaths)
 47→        if(message){
 48→          console.log(message.message)
 49→        }
 50→
 51→      }
 52→        editor.update(() => {
 53→            const state = editor.getEditorState().toJSON();
 54→            console.log(state)
 55→
 56→            const root = $getRoot();
 57→            root.clear();
 58→            onClose();
 59→        })
 60→    }, [editor, onClose, session?.access_token, uploadedImagePaths])
 61→
 62→    const handleCloseEditorOnSave = useCallback(async() => {
 63→      editor.update(() => {
 64→            const state = editor.getEditorState().toJSON();
 65→            console.log(state)
 66→
 67→            const root = $getRoot();
 68→            root.clear();
 69→            onClose();
 70→      })
 71→    }, [onClose, editor])
 72→
 73→    return(
 74→        <>
 75→        <div className='editor-parent-container'>
 76→
 77→            <motion.div
 78→            initial={{scale: 0, opacity: 0.8}}
 79→            animate={{scale: 1, opacity: 1}}
 80→            exit={{scale: 0.8, opacity: 0,}}
 81→            transition={{type: 'spring', stiffness: 260, damping: 25}}
 82→            className={`editor-container ${editorMode === 'canvas' ? 'is-canvas-mode' : ''}`}
 83→            >
 84→                <div className='editor-close-bttn-container'>
 85→                    <button
 86→                        onClick={() => handleCloseEditor()}
 87→                        className='editor-close-bttn'
 88→                        aria-label="Close editor"
 89→                        title="Close"
 90→                    >
 91→                        <svg xmlns="http://www.w3.org/2000/svg" height="24px" viewBox="0 -960 960 960" width="24px" fill="currentColor"><path d="m256-200-56-56 224-224-224-224 56-56 224 224 224-224 56 56-224 224 224 224-56 56-224-224-224 224Z"/></svg>
 92→                    </button>
 93→                </div>
 94→
 95→                <input value={title} onChange={(e) => setTitle(e.target.value)} className='content-title-input' type="text" placeholder='Title' />
 96→
 97→                <div className='canvas-editor-controls' style={{marginBottom: "0.55rem"}}>
 98→                    <button
 99→                        type="button"
100→                        onClick={() => setEditorMode('text')}
101→                        className={`canvas-control-btn ${editorMode === 'text' ? 'is-active' : ''} composer-mode-btn`}
102→                    >
103→                        <svg xmlns="http://www.w3.org/2000/svg" height="18px" viewBox="0 -960 960 960" width="18px" fill="currentColor"><path d="M160-200v-80h240v-80H240q-33 0-56.5-23.5T160-440v-200q0-33 23.5-56.5T240-720h480v80H240v200h480v80H560v80h240v80H160Z"/></svg>
104→                        Text Post
105→                    </button>
106→                    <button
107→                        type="button"
108→                        onClick={() => setEditorMode('canvas')}
109→                        className={`canvas-control-btn ${editorMode === 'canvas' ? 'is-active' : ''} composer-mode-btn`}
110→                    >
111→                        <svg xmlns="http://www.w3.org/2000/svg" height="18px" viewBox="0 -960 960 960" width="18px" fill="currentColor"><path d="M480-80q-83 0-156-31.5T197-197q-54-54-85.5-127T80-480q0-83 31.5-156T197-763q54-54 127-85.5T480-880q63 0 121.5 18.5T709-807q-17 19-26 44t-9 52q0 53 37.5 90.5T802-583q27 0 52-9t44-26q36 49 54 107.5T970-480q0 83-31.5 156T853-197q-54 54-127 85.5T570-80H480Zm-12-196q30 0 51-21t21-51q0-30-21-51t-51-21q-30 0-51 21t-21 51q0 30 21 51t51 21Zm-153-84q24 0 42-18t18-42q0-24-18-42t-42-18q-24 0-42 18t-18 42q0 24 18 42t42 18Zm6-189q17 0 28.5-11.5T361-589q0-17-11.5-28.5T321-629q-17 0-28.5 11.5T281-589q0 17 11.5 28.5T321-549Zm183-66q36 0 60-24t24-60q0-36-24-60t-60-24q-36 0-60 24t-24 60q0 36 24 60t60 24Z"/></svg>
112→                        Switch to Canvas
113→                    </button>
114→                </div>
115→
116→                <div className={`editor-mode-shell ${editorMode === 'canvas' ? 'is-canvas-mode' : ''}`}>
117→                    <ErrorBoundary>
118→                        {editorMode === 'text' ? (
119→                            <EditorInner
120→                                addUploadImagesPath={addUploadedImagePath}
121→                                onclose={handleCloseEditor}
122→                                onCloseOnSave={handleCloseEditorOnSave}
123→                                title={title}
124→                                setWordCount={setWordCount}
125→                                wordCount={wordCount}
126→                                onSwitchToCanvas={() => setEditorMode('canvas')}
127→                            />
128→                        ) : (
129→                            <CanvasEditor
130→                                title={title}
131→                                onCloseOnSave={handleCloseEditorOnSave}
132→                                addUploadedImagePath={addUploadedImagePath}
133→                                initialCanvasDoc={initialCanvasDoc}
134→                                remixSource={remixSource}
135→                            />
136→                        )}
137→                    </ErrorBoundary>
138→                </div>
139→            </motion.div>
140→        </div>
141→        </>
142→    )
143→}
144→export default Editor;
