334→    font-style: italic;
335→}
336→
337→/* ── Footer bar (word count + save) ── */
338→.editor-footer {
339→    display: flex;
340→    justify-content: space-between;
341→    align-items: center;
342→    padding: 0.5rem 0;
343→    border-top: 1px solid var(--editor-border);
344→    margin-top: auto;
