372→}
373→.editor-save-bttn:hover {
374→    opacity: 0.9;
375→}
376→.editor-save-bttn:active {
377→    transform: scale(0.98);
378→}
379→.editor-save-bttn:focus {
380→    outline: none;
381→}
382→.editor-save-bttn-disabled {
383→    display: flex;
384→    justify-content: center;
385→    align-items: center;
386→    padding: 0.5rem 1.25rem;
387→    border-radius: 15px;
388→    background-color: var(--bg-pill);
389→    color: var(--text-muted);
390→    font-weight: 650;
391→    user-select: none;
392→    border: none;
393→    cursor: not-allowed;
394→}
395→.editor-save-bttn-disabled:focus {
396→    outline: none;
397→}
398→
399→.composer-mode-btn{
400→    display: inline-flex;
401→    align-items: center;
402→    gap: 0.35rem;
403→    font-weight: 600;
404→}
405→
406→/* ── Image upload icon (inside toolbar) ── */
407→.editor-upload-image-icon {
408→    padding: 0.4rem;
409→    border-radius: 6px;
410→    cursor: pointer;
411→    transition: all 0.15s ease;
412→}
413→.editor-upload-image-icon:hover {
414→    background-color: var(--bg-pill);
415→}
416→
417→/* ── Image components ── */
418→.image-container {
419→    display: flex;
420→    justify-content: center;
421→    width: 100%;
422→    height: fit-content;
423→}
424→.image-wrapper {
425→    position: relative;
426→    display: flex;
427→    justify-content: flex-end;
428→    margin: 1rem 0;
429→    width: fit-content;
430→    height: fit-content;
431→}
432→.image-actions {
433→    position: absolute;
434→    display: flex;
435→    gap: 0.3rem;
436→    top: 0;
437→    right: 0;
438→    margin: 0.5rem;
439→    z-index: 11;
440→}
441→.image-action-btn {
442→    display: flex;
443→    align-items: center;
444→    justify-content: center;
445→    padding: 0.4rem;
446→    border-radius: 50%;
447→    cursor: pointer;
448→    transition: ease-in-out 0.1s;
449→    background-color: rgba(0, 0, 0, 0.35);
