472→.southeast-side-handle {
473→    position: absolute;
474→    bottom: -4px;
475→    right: -4px;
476→    width: 12px;
477→    height: 12px;
478→    background-color: var(--bg-pill);
479→    border: 1px solid var(--editor-text);
480→    border-radius: 50%;
481→    cursor: nwse-resize;
482→    z-index: 10;
483→}
484→.southwest-side-handle {
485→    position: absolute;
486→    bottom: -4px;
487→    left: -4px;
488→    width: 12px;
489→    height: 12px;
490→    background-color: var(--bg-pill);
491→    border: 1px solid var(--editor-text);
492→    border-radius: 50%;
493→    cursor: nesw-resize;
494→    z-index: 10;
495→}
496→.northeast-side-handle {
497→    position: absolute;
498→    top: -4px;
499→    right: -4px;
500→    width: 12px;
501→    height: 12px;
502→    background-color: var(--bg-pill);
503→    border: 1px solid var(--editor-text);
504→    border-radius: 50%;
505→    cursor: sw-resize;
506→    z-index: 10;
507→}
508→.northwest-side-handle {
